@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
}

#saleListBox {
  font-family: "Figtree", sans-serif;
  padding: 0;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
}

.widget-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 14px 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

.widget-header-icon {
  width: 26px;
  height: 26px;
  border-radius: 8px;
  background: rgba(5, 4, 46, 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #05042E;
  font-size: 13px;
  flex-shrink: 0;
}

.widget-header span {
  font-size: 10px;
  font-weight: 700;
  color: #05042E;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

#platformRow {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

#platformRow label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  white-space: nowrap;
}

#platformSelect {
  flex: 1;
  padding: 7px 10px;
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  background: #fff;
  outline: none;
}

#platformSelect:focus {
  border-color: #469BC0;
}

#saleTable {
  width: 100%;
  border-collapse: collapse;
}

#saleTable th {
  text-align: left;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #888780;
  font-weight: 700;
  padding: 8px 12px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

#saleTable td {
  padding: 8px 12px;
  font-size: 13px;
  font-weight: 600;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  color: #05042E;
}

#saleTable tr:last-child td {
  border-bottom: none;
}

.priceInput {
  width: 70px;
  padding: 5px 7px;
  font-family: "Figtree", sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: #05042E;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  outline: none;
}

.priceInput:focus {
  border-color: #469BC0;
}

.fee-cell {
  color: #888780;
}

.removeBtn {
  background: none;
  border: none;
  color: #991b1b;
  font-size: 16px;
  cursor: pointer;
  line-height: 1;
  padding: 4px 6px;
}

.removeBtn:hover {
  color: #7f1d1d;
}

.empty-row {
  text-align: center;
  color: #888780;
  font-weight: 600;
  padding: 20px 0;
  font-size: 12px;
}

#saleTotalRow {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 16px;
  background: rgba(5, 4, 46, 0.04);
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
  font-weight: 700;
  font-size: 14px;
  color: #05042E;
}

#processOrderBtn {
  width: 100%;
  padding: 11px;
  font-family: "Figtree", sans-serif;
  background: #A3E851;
  color: #05042E;
  font-weight: 700;
  font-size: 12px;
  border: none;
  cursor: pointer;
  transition: background 0.15s;
}

#processOrderBtn:hover {
  background: #5DC987;
}

